import numpy as np

def rbf_center_placement(X, n_centers, strategy='random', random_seed=42):
    np.random.seed(random_seed)
    n_samples, n_features = X.shape

    if strategy == 'random':
        indices = np.random.choice(n_samples, size=n_centers, replace=False)
        centers = X[indices].copy()

    elif strategy == 'maxmin':
        first_idx = np.random.randint(0, n_samples)
        selected = [first_idx]
        # min distance from each point to any selected center
        min_dists = np.full(n_samples, np.inf)
        # update min_dists with distance to first center
        diff = X - X[first_idx]
        min_dists = np.minimum(min_dists, np.sqrt(np.sum(diff**2, axis=1)))
        for _ in range(n_centers - 1):
            next_idx = np.argmax(min_dists)
            selected.append(next_idx)
            diff = X - X[next_idx]
            dists_to_new = np.sqrt(np.sum(diff**2, axis=1))
            min_dists = np.minimum(min_dists, dists_to_new)
        centers = X[selected].copy()

    elif strategy == 'kmeans':
        init_indices = np.random.choice(n_samples, size=n_centers, replace=False)
        centers = X[init_indices].copy()
        for _ in range(100):
            # compute distances: (n_samples, n_centers)
            dists = np.sqrt(((X[:, np.newaxis, :] - centers[np.newaxis, :, :])**2).sum(axis=2))
            labels = np.argmin(dists, axis=1)
            new_centers = np.array([
                X[labels == k].mean(axis=0) if np.any(labels == k) else centers[k]
                for k in range(n_centers)
            ])
            if np.max(np.abs(new_centers - centers)) < 1e-8:
                break
            centers = new_centers
        centers = new_centers
    else:
        raise ValueError(f"Unknown strategy: {strategy}")

    # compute width
    if n_centers == 1:
        width = 1.0
    else:
        # max pairwise distance between centers
        d_max = 0.0
        for i in range(n_centers):
            for j in range(i + 1, n_centers):
                d = np.sqrt(np.sum((centers[i] - centers[j])**2))
                if d > d_max:
                    d_max = d
        width = d_max / np.sqrt(2 * n_centers)

    return {
        'centers': np.round(centers, 4),
        'width': round(float(width), 4)
    }
